module freq_divbyfrac #(
    parameter MUL2_DIV_CLK = 7
) (
    input               rst_n,
    input               clk,
    output              clk_div
);

reg [1:0] count;
reg div_clk;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        count <= 0;
        div_clk <= 0;
    end else begin
        count <= count + 1;
        if (count == MUL2_DIV_CLK - 1) begin
            div_clk <= ~div_clk;
            count <= 0;
        end
    end
end

assign clk_div = div_clk;

endmodule
